1: const std = @import("std");
2: const assert = std.debug.assert;
3: const expectEqual = std.testing.expectEqual;
4: 
5: const Diacritic = enum(u8) {
6:     empty, // nguyên âm, không dấu.
7:     circumflex, // dấu nón: â, ô, ê.
8:     horn, // dấu móc: ư, ơ.
9:     breve, // dấu ă.
10:     bar, // dấu gạch: đ.
11: };
12: 
13: const Tone = enum(u8) {
14:     level, // thanh ngang, không dấu.
15:     rising, // sắc.
16:     falling, // huyền.
17:     dipping_rising, // hỏi.
18:     rising_glottalized, // ngã.
19:     falling_glottalized, // nặng.
20: };
21: 
22: const Span = extern struct {
23:     // Alphabet ASCII character, could be lowercase or uppercase.
24:     base: u8,
25:     // By default, it's plain alphabet character.
26:     diacritic: Diacritic = .empty,
27:     // By default, no tone is placed.
28:     tone: Tone = .level,
29: 
30:     // Create a Span with plain alphabet character, no diacritic, no tone.
31:     pub fn init(base: u8) Span {
32:         return Span.init_diacritic_tone(base, .empty, .level);
33:     }
34: 
35:     // Create a Span with diacritic, no tone.
36:     pub fn init_diacritic(base: u8, diacritic: Diacritic) Span {
37:         return Span.init_diacritic_tone(base, diacritic, .level);
38:     }
39: 
40:     pub fn init_diacritic_tone(base: u8, diacritic: Diacritic, tone: Tone) Span {
41:         // Only allow a-zA-Z.
42:         assert(std.ascii.isAlphabetic(base));
43: 
44:         // Only allow a valid Vietnamese alphabet combinations.
45:         switch (diacritic) {
46:             // All alphabet is allowed without diacritic.
47:             .empty => {},
48:             // Only a, o, e are valid with circumflex.
49:             .circumflex => switch (base) {
50:                 'A', 'E', 'O', 'a', 'e', 'o' => {},
51:                 else => unreachable,
52:             },
53:             // Only u, o are valid with horn.
54:             .horn => switch (base) {
55:                 'O', 'U', 'o', 'u' => {},
56:                 else => unreachable,
57:             },
58:             // Only a is valid with breve.
59:             .breve => switch (base) {
60:                 'A', 'a' => {},
61:                 else => unreachable,
62:             },
63:             // Only d is valid with bar.
64:             .bar => switch (base) {
65:                 'D', 'd' => {},
66:                 else => unreachable,
67:             },
68:         }
69: 
70:         // Only allow tone on valid Vietnamese vowels based on Vietnamese rules.
71:         switch (tone) {
72:             // All alphabet is allowed with level.
73:             .level => {},
74:             // All vowels is allowed with remaining tones.
75:             .rising, .falling, .dipping_rising, .rising_glottalized, .falling_glottalized => switch (base) {
76:                 'A', 'E', 'I', 'O', 'U', 'Y', 'a', 'e', 'i', 'o', 'u', 'y' => {},
77:                 else => unreachable,
78:             },
79:         }
80: 
81:         return .{ .base = base, .diacritic = diacritic, .tone = tone };
82:     }
83: };
84: 
85: test "expect Span.init allows alphabet characters" {
86:     for ("ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz") |c| {
87:         // Act
88:         const sp = Span.init(c);
89: 
90:         // Assert
91:         try expectEqual(c, sp.base);
92:         try expectEqual(.empty, sp.diacritic);
93:         try expectEqual(.level, sp.tone);
94:     }
95: }
96: 
97: test "expect Span.init_diacritic can construct any alphabet characters" {
98:     for ("ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz") |c| {
99:         // Act
100:         const sp = Span.init_diacritic(c, .empty);
101: 
102:         // Assert
103:         try expectEqual(c, sp.base);
104:         try expectEqual(.empty, sp.diacritic);
105:         try expectEqual(.level, sp.tone);
106:     }
107: }
108: 
109: test "expect Span.init_diacritic can construct any Vietnamese characters" {
110:     const chars = .{
111:         .{ .base = 'A', .diacritic = .breve }, // Ă.
112:         .{ .base = 'a', .diacritic = .breve }, // ă.
113:         .{ .base = 'A', .diacritic = .circumflex }, // Â.
114:         .{ .base = 'a', .diacritic = .circumflex }, // â.
115:         .{ .base = 'E', .diacritic = .circumflex }, // Ê.
116:         .{ .base = 'e', .diacritic = .circumflex }, // ê.
117:         .{ .base = 'O', .diacritic = .circumflex }, // Ô.
118:         .{ .base = 'o', .diacritic = .circumflex }, // ô.
119:         .{ .base = 'O', .diacritic = .horn }, // Ơ.
120:         .{ .base = 'o', .diacritic = .horn }, // ơ.
121:         .{ .base = 'U', .diacritic = .horn }, // Ư.
122:         .{ .base = 'u', .diacritic = .horn }, // ư.
123:         .{ .base = 'D', .diacritic = .bar }, // Đ.
124:         .{ .base = 'd', .diacritic = .bar }, // đ.
125:     };
126: 
127:     // Need `inline for` to know the tuple at comptime.
128:     inline for (chars) |c| {
129:         // Act
130:         const sp = Span.init_diacritic(c.base, c.diacritic);
131: 
132:         // Assert
133:         try expectEqual(c.base, sp.base);
134:         try expectEqual(c.diacritic, sp.diacritic);
135:         try expectEqual(.level, sp.tone);
136:     }
137: }
138: 
139: test "expect Span.init_diacritic_tone can construct all vowels with all tones" {
140:     // Act
141:     const sp = Span.init_diacritic_tone('A', .circumflex, .rising);
142: 
143:     // Assert
144:     try expectEqual('A', sp.base);
145:     try expectEqual(.circumflex, sp.diacritic);
146:     try expectEqual(.rising, sp.tone);
147: }
