149: const InputMode = enum(u8) {
150:     // By pass Vietnamese input processing and append the character as is.
151:     literal,
152:     // Process Vietnamese input in Telex input method.
153:     telex,
154: };
155: 
156: const State = extern struct {
157:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
158:     // longer than 16.
159:     buffer_effective: [16]Span,
160:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
161:     // value (256), we will reset the effective buffer and this value.
162:     buffer_length: u8,
163:     // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
164:     // switch, input cancellation, exceed effective buffer). This value is independent from mode and
165:     // has higher priority, e.g. if the mode is `telex` but the engine is working on position on or
166:     // after literal index, the engine will skip Vietnamese input processing (we only count positive
167:     // value, -1 mean no literal index).
168:     literal_start_index: i8,
169:     // Determine if we will process input in the specified mode (Telex) or append the character as is.
170:     mode: InputMode = .literal,
171: };
